import java.util.ArrayDeque

/**
 * A string is "coherent" if it does not contain "011" or "110" as a subsequence.
 * We want to find the minimum number of flips to make s coherent.
 *
 * A string is coherent if and only if it is of the form:
 * 1. All zeros: "00...0"
 * 2. All ones: "11...1"
 * 3. Zeros followed by ones: "00...011...1" (i.e., there is at most one transition from 0 to 1)
 *
 * Let's analyze the forbidden subsequences:
 * "011" subsequence requires a '0' followed by two '1's.
 * "110" subsequence requires two '1's followed by a '0'.
 *
 * Case 1: Form "0...0"
 * Any string of all zeros is coherent.
 * The cost to transform s to "0...0" is the count of '1's in s.
 *
 * Case 2: Form "1...1"
 * Any string of all ones is coherent.
 * The cost to transform s to "1...1" is the count of '0's in s.
 *
 * Case 3: Form "0...01...1" (at most one transition)
 * This means the string is composed of a prefix of '0's and a suffix of '1's.
 * Let the split point be k (0 <= k <= n), where the string is s'[0..k-1] = '0' and s'[k..n-1] = '1'.
 *
 * For a fixed split point k, the cost is:
 * Cost(k) = (Number of '1's in s[0..k-1]) + (Number of '0's in s[k..n-1])
 * We need to find min(Cost(k)) for all k in [0, n].
 *
 * k=0: String is all '1's. Cost = (1s in empty prefix) + (0s in s) = 0 + count('0' in s). (Matches Case 2)
 * k=n: String is all '0's. Cost = (1s in s) + (0s in empty suffix) = count('1' in s) + 0. (Matches Case 1)
 *
 * The overall minimum cost is min(min_k(Cost(k)), cost_all_zeros, cost_all_ones).
 * Since Cost(0) and Cost(n) cover the all-ones and all-zeros cases, we just need to find min_k(Cost(k)).
 */
fun solve(s: String): Long {
    val n = s.length
    if (n == 0) return 0L

    // Precompute prefix sums for '1's and suffix sums for '0's for efficient calculation of Cost(k).
    // prefixOnes[i] = number of '1's in s[0...i-1] (length i prefix)
    val prefixOnes = IntArray(n + 1)
    for (i in 0 until n) {
        prefixOnes[i + 1] = prefixOnes[i] + if (s[i] == '1') 1 else 0
    }

    // suffixZeros[i] = number of '0's in s[i...n-1] (suffix starting at index i)
    val suffixZeros = IntArray(n + 1)
    for (i in n - 1 downTo 0) {
        suffixZeros[i] = suffixZeros[i + 1] + if (s[i] == '0') 1 else 0
    }

    var minFlips = Long.MAX_VALUE

    // Iterate over all possible split points k, where k is the length of the '0' prefix.
    // The resulting string is 0...0 (k times) followed by 1...1 (n-k times).
    // k ranges from 0 (all 1s) to n (all 0s).
    for (k in 0..n) {
        // Cost = (Number of '1's in the target 0-prefix s[0..k-1]) 
        //      + (Number of '0's in the target 1-suffix s[k..n-1])

        // Number of '1's in s[0..k-1] is prefixOnes[k]
        val onesInPrefix = prefixOnes[k]

        // Number of '0's in s[k..n-1] is suffixZeros[k]
        val zerosInSuffix = suffixZeros[k]

        val currentCost = onesInPrefix + zerosInSuffix

        if (currentCost < minFlips) {
            minFlips = currentCost.toLong()
        }
    }

    return minFlips
}
